// src/components/LandList.js
import React from 'react';

const LandList = ({ records }) => {
  return (
    <div>
      {records.length === 0 ? (
        <p>No land records found.</p>
      ) : (
        records.map((record, index) => (
          <div key={index}>
            <p><strong>{record.land_name}</strong></p>
            <p>Survey Number: {record.survey_number}</p>
            <p>Owner: {record.owner_name}</p>
            <p>Area: {record.area} sq. meters</p>
            <p>Location: {record.location}</p>
          </div>
        ))
      )}
    </div>
  );
};

export default LandList;
